import{_ as e,o as a,c as n,a0 as t}from"./chunks/framework.jwovEGr5.js";const i="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",g=JSON.parse('{"title":"Suspension & Limited Mode","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/suspension.md","filePath":"subscriptions/suspension.md"}'),o={name:"subscriptions/suspension.md"};function l(r,s,p,d,u,h){return a(),n("div",null,[...s[0]||(s[0]=[t('<h1 id="suspension-limited-mode" tabindex="-1">Suspension &amp; Limited Mode <a class="header-anchor" href="#suspension-limited-mode" aria-label="Permalink to &quot;Suspension &amp; Limited Mode&quot;">​</a></h1><p><strong><a href="./../getting-started/glossary.html#suspension">Suspension</a></strong> is a paused, mostly read-only state for a kingdom or alliance. It happens either because a hard limit was reached, or because a Supreme Admin paused the scope on purpose. This page explains why it happens, what still works, and how it ends.</p><h2 id="what-suspension-feels-like" tabindex="-1">What suspension feels like <a class="header-anchor" href="#what-suspension-feels-like" aria-label="Permalink to &quot;What suspension feels like&quot;">​</a></h2><p>A suspended kingdom or alliance shows a <strong>banner</strong> explaining the situation, and new changes are blocked. You can still see your data — it&#39;s a pause, not a deletion.</p><p><img src="'+i+`" alt="Suspension banner in limited mode"></p><h2 id="why-a-scope-gets-suspended-the-reasons" tabindex="-1">Why a scope gets suspended (the reasons) <a class="header-anchor" href="#why-a-scope-gets-suspended-the-reasons" aria-label="Permalink to &quot;Why a scope gets suspended (the reasons)&quot;">​</a></h2><p>A suspension always has a <strong>reason</strong>. The reason matters, because it decides whether the pause spreads from a kingdom down to its alliances:</p><table tabindex="0"><thead><tr><th>Reason</th><th>Set by</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Usage limit</strong></td><td>Automatic</td><td>A hard resource limit was reached. This is the &quot;you filled something up&quot; case.</td></tr><tr><td><strong>Manual</strong></td><td>Supreme Admin</td><td>Paused by hand for a general reason.</td></tr><tr><td><strong>Admin</strong></td><td>Supreme Admin</td><td>An administrative pause.</td></tr><tr><td><strong>Abuse</strong></td><td>Supreme Admin</td><td>Paused due to misuse.</td></tr><tr><td><strong>Global</strong></td><td>Supreme Admin</td><td>A platform-wide administrative pause.</td></tr></tbody></table><blockquote><p><strong>Automatic usage-limit suspension:</strong> when a kingdom or alliance fills a hard-limited resource to 100%, the app can place it into usage-limit mode on its own. The good news is it also <strong>lifts on its own</strong> once you clean up enough — see &quot;How it ends,&quot; below.</p></blockquote><h2 id="does-a-kingdom-s-suspension-affect-its-alliances-cascade" tabindex="-1">Does a kingdom&#39;s suspension affect its alliances? (cascade) <a class="header-anchor" href="#does-a-kingdom-s-suspension-affect-its-alliances-cascade" aria-label="Permalink to &quot;Does a kingdom&#39;s suspension affect its alliances? (cascade)&quot;">​</a></h2><p>When a <strong>kingdom</strong> is suspended, whether that pause reaches the alliances inside it depends on the reason — and on whether an alliance stands on its own plan.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        KINGDOM is suspended</span></span>
<span class="line"><span>                │</span></span>
<span class="line"><span>        what&#39;s the reason?</span></span>
<span class="line"><span>        │                          │</span></span>
<span class="line"><span>  &quot;usage limit&quot;            &quot;manual / admin / abuse / global&quot;</span></span>
<span class="line"><span>        │                          │</span></span>
<span class="line"><span>        ▼                          ▼</span></span>
<span class="line"><span>  Does the alliance          Does the alliance have a</span></span>
<span class="line"><span>  have its OWN paid          Supreme-Admin override for</span></span>
<span class="line"><span>  (direct) plan?             parent suspension?</span></span>
<span class="line"><span>     │        │                 │            │</span></span>
<span class="line"><span>    yes       no               yes           no</span></span>
<span class="line"><span>     │        │                 │            │</span></span>
<span class="line"><span>     ▼        ▼                 ▼            ▼</span></span>
<span class="line"><span>  SURVIVES  paused          SURVIVES       paused</span></span>
<span class="line"><span> (keeps     with the       (exempted)     with the</span></span>
<span class="line"><span>  working)  kingdom                        kingdom</span></span></code></pre></div><p>In words:</p><ul><li><strong>An alliance&#39;s own suspension</strong> always pauses that alliance, no matter what.</li><li>For a <strong>usage-limit</strong> kingdom suspension: an alliance that has its <strong>own direct paid plan survives</strong> — it keeps working. An alliance riding on the free tier (or only on a grant) is paused along with the kingdom.</li><li>For the <strong>harder reasons</strong> (manual, admin, abuse, global): the pause cascades to alliances <strong>unless</strong> a Supreme Admin has given that alliance a specific override.</li></ul><p>This &quot;own plan survives a usage-limit kingdom pause&quot; rule is the main reason an alliance might choose a <a href="./direct-alliance-subscription.html">direct subscription</a>.</p><h2 id="what-still-works-in-limited-mode" tabindex="-1">What still works in limited mode <a class="header-anchor" href="#what-still-works-in-limited-mode" aria-label="Permalink to &quot;What still works in limited mode&quot;">​</a></h2><p>A suspended (limited) scope keeps <strong>read access</strong> and allows <strong>cleanup</strong>, while blocking new changes. In practice that means you can still view your data and run a <a href="./cleanup.html">cleanup</a>, but adding or changing things is turned off until the pause lifts.</p><blockquote><p><strong>Exactly which buttons are disabled</strong> in limited mode is best confirmed in the app itself — when a scope is suspended, the on-screen banner and the disabled controls show you precisely what&#39;s blocked. Rather than memorize a list, rely on the banner: if an action is unavailable, that&#39;s limited mode at work. (The general rule holds: viewing and cleanup stay available; creating and editing are blocked.)</p></blockquote><h2 id="how-suspension-ends" tabindex="-1">How suspension ends <a class="header-anchor" href="#how-suspension-ends" aria-label="Permalink to &quot;How suspension ends&quot;">​</a></h2><ul><li><strong>Usage-limit (automatic):</strong> clean up enough that usage drops back to a safe level (around 95% or below) and the app <strong>automatically restores</strong> the scope. See <a href="./cleanup.html">Run a Cleanup</a>. This is the fastest path — you&#39;re in control.</li><li><strong>Manual / admin / abuse / global:</strong> only a <strong>Supreme Admin</strong> can lift these, by unsuspending the scope. If you&#39;re paused for one of these reasons, contact your Supreme Admin.</li></ul><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./cleanup.html">Run a Cleanup</a> — the way out of a usage-limit suspension.</li><li><a href="./quota-warnings.html">Quota Warnings</a> — catching problems before they become a suspension.</li><li><a href="./direct-alliance-subscription.html">Direct Alliance Subscriptions</a> — how an own plan survives a kingdom usage-limit pause.</li></ul>`,22)])])}const m=e(o,[["render",l]]);export{g as __pageData,m as default};
